def fmt(v, dec=2):
    if isinstance(v, float) or isinstance(v, int):
        return f"{v:+.2f}"
    return str(v)

def build_holdings_js(rows):
    parts = []
    for r in rows:
        parts.append(f"['{r[0]}','{r[1]}','{r[2]}','{r[3]}',{r[4]},{r[5]},{r[6]},'{fmt(r[4])}%','{fmt(r[5])}%','{fmt(r[6])}%','{r[9]:.2f}%','{'vg' if r[4]>=0 else 'vr'}','{'vg' if r[5]>=0 else 'vr'}','{'vg' if r[6]>=0 else 'vr'}']")
    return "[\n      " + ",\n      ".join(parts) + "\n    ]"

def build_indices_js(rows):
    parts = []
    for r in rows:
        parts.append(f"['{r[0]}','{r[1]}','{fmt(r[2])}%','{fmt(r[3])}%','{fmt(r[4])}%','{fmt(r[5])}%','{fmt(r[6])}%','{'vg' if r[2]>=0 else 'vr'}']")
    return "[\n      " + ",\n      ".join(parts) + "\n    ]"

def build_products():
    parts = []
    for key, p in PRODUCTS.items():
        h = build_holdings_js(p['holdings'])
        i = build_indices_js(p['indices'])
        parts.append(f"  '{key}': {{name:'{p['name']}',code:'{p['code']}',partner:'{p['partner']}',index:'{p['index']}',scale:'{p['scale']}',nav:'{p['nav']}',change:'{p['change']}',up:{str(p['up']).lower()},desc:'{p['desc']}',holdings:{h},indices:{i}}}")
    return ",\n\n".join(parts)

print("Building products section...")
